//vip.opstream90.com/20260304/26312_7ea7fde0/index.m3u8"},{"name":"36","slug":"36","filename":"Purple River S2 - Tập 36---2025","link_embed":"https://vip.opstream90.com/share/43b5c2f6a840417e79ed8bb3feeeeaf5","link_m3u8":"https://vip.opstream90.com/20260311/26911_43b5c2f6/index.m3u8"}]}],"time":"20 phút/tập","description":"<p>Truyền kì máu lửa qua từng thời đại: Trong đế quốc của loài người, gia tộc thần bí ở phương Đông xa xôi, Tử Xuyên Tam Kiệt phất lên! Anh cả Đế Lâm chín chắn đa mưu, tàn khốc lí trí, anh hai Sterling chỉ huy một đội quân, có lòng trung thành với nước, em út Tử Xuyên Tú bị người đời gọi với cái tên “Vô Lại”, trí dũng song toàn. Gia tộc Tử Xuyên loạn trong giặc ngoài, Tử Xuyên Tam Kiệt mỗi người đều có thế mạnh riêng: Trong thời khắc nước sôi lửa bỏng, đánh bại Ma tộc hung ác, xông vào hang hổ truy sát tên phản đồ Lôi Hồng đến cùng; Tư Đặc Lâm lấy gia tộc làm gốc, vừa vô tình vừa trọng tình lưu luyến người yêu... Loài người, Ma tộc, Thú tộc. Mỗi tộc ở mỗi phương khác nhau, tranh chấp lẫn nhau trên mảnh đất Đại Lục này, xích mích không ngừng. Khi máu và lửa hòa vào nhau, đao và kiếm va chạm, tạo ra câu chuyện sử thi bi tráng-Tử Xuyên.</p>","tmdb":{"type":"tv","id":"153869","season":2,"vote_average":8.5,"vote_count":2},"modified":"2026-03-11T10:04:57.000Z"},{"id":"6894a0660aea55b598ef3bf4","_id":"6894a0660aea55b598ef3bf4","title":"Làm Giàu Với Ma 2: Cuộc Chiến Hột Xoàn","origin_name":"Betting with Ghost 2: The Gem Hunter","slug":"lam-giau-voi-ma-2-cuoc-chien-hot-xoan","thumb":"/uploads/movies/lam-giau-voi-ma-2-cuoc-chien-hot-xoan-thumb.jpg","poster":"","year":2025,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"},{"id":"620f3d2b91fa4af90ab697fe","name":"Chính kịch","slug":"chinh-kich"}],"country":[{"id":"63e0fd3ecaf0f6e22aeb0616","name":"Việt Nam","slug":"viet-nam"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k"